const {
  customer_name,
  customer_email,
  customer_phone,
  club_name,
  quantity,
  timeline,
  agent_summary,
  source,
  sessionId
} = $json.body;

const nameParts = (customer_name || '').trim().split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

return {
  contact: {
    email: customer_email || '',
    firstName: firstName,
    lastName: lastName,
    phone: customer_phone || ''
  },
  club: {
    name: (club_name || '').trim()
  },
  inquiry: {
    name: `${club_name} - ${new Date().toISOString().split('T')[0]}`,
    quantity: quantity || '',
    timeline: timeline || '',
    source: source || 'Website Chatbot',
    sessionId: sessionId || '',
    agent_summary: agent_summary || ''
  },
  raw: $json.body
};

